// Accept either a full atlas-api transaction object (from POST /transactions response)
// or a {payload: {...}} envelope (from /actions/trigger-workflow).
const raw = $json;
const tx = raw.payload || raw;
// Fall back to required fields with sane defaults so the LLM call doesn't blow up
return [{ json: {
  id: tx.id || tx.transaction_id || null,
  amount: tx.amount,
  category: tx.category,
  vendor_id: tx.vendor_id,
  vendor_name: tx.vendor_name || null,
  description: tx.description || null
}}];

parameters.jsonBody:
={{ JSON.stringify({
  model: 'Zivo Fast (GPT-5 Mini)',
  response_format: { type: 'json_object' },
  temperature: 0.1,
  messages: [
    { role: 'system', content: 'You are an expense policy auditor for Atlas Operations. Reply with JSON only: {"flagged": boolean, "severity": "low"|"medium"|"high", "reason": string}. Flag transactions when: amount > $4000 (any category), amount > $1500 for meals/travel, vendor name suggests irregularity, or description hints at policy violation.' },
    { role: 'user', content: `Review this transaction:\nAmount: $${$json.amount}\nCategory: ${$json.category}\nVendor: ${$json.vendor_name || 'unknown'}\nDescription: ${$json.description || 'n/a'}` }
  ]
}) }}

