// Parse the LLM verdict and normalize
let verdict = { flagged: false, severity: 'low', reason: 'parse_error' };
try {
  const content = $json.choices[0].message.content;
  verdict = JSON.parse(content);
} catch (e) {
  // leave default verdict
}
const tx = $('Normalize input').first().json;
return [{ json: {
  transaction_id: tx.id,
  flagged: !!verdict.flagged,
  severity: verdict.severity || 'low',
  policy_violation: verdict.flagged ? (verdict.reason || 'unspecified') : null
}}];

